import React, { useState, useEffect, useCallback } from 'react';
import { registrationAPI } from '../services/api';
import { useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';

const inp = { width:'100%', padding:'10px 12px', border:'1.5px solid #E5E7EB', borderRadius:9, fontSize:13, outline:'none', fontFamily:'inherit', background:'#fff', boxSizing:'border-box' };
const lbl = { display:'block', fontSize:11, fontWeight:700, color:'#4B5563', textTransform:'uppercase', letterSpacing:'.06em', marginBottom:6 };
const CLASSES = ['Class 1','Class 2','Class 3','Class 4','Class 5','Class 6','Class 7','Class 8','Class 9','Class 10','Class 11','Class 12'];
const MOCK = [
  { id:1, registration_no:'REG001', student_name:'Riya Gupta',   parent_name:'Sanjay Gupta',  mobile:'9811001100', desired_class:'Class 6', registration_fee:500, fee_paid:true,  created_at:'2025-06-05', status:'pending' },
  { id:2, registration_no:'REG002', student_name:'Rahul Sharma', parent_name:'Amit Sharma',   mobile:'9822002200', desired_class:'Class 9', registration_fee:500, fee_paid:false, created_at:'2025-06-04', status:'pending' },
  { id:3, registration_no:'REG003', student_name:'Pooja Verma',  parent_name:'Dinesh Verma',  mobile:'9833003300', desired_class:'Class 7', registration_fee:500, fee_paid:true,  created_at:'2025-06-03', status:'converted' },
];

export default function Registration() {
  const navigate = useNavigate();
  const [regs,      setRegs]      = useState([]);
  const [loading,   setLoading]   = useState(true);
  const [isMock,    setIsMock]    = useState(false);
  const [total,     setTotal]     = useState(0);
  const [showAdd,   setShowAdd]   = useState(false);
  const [showAddCls,setShowAddCls]= useState(false);
  const [converting,setConverting]= useState(null);
  const [saving,    setSaving]    = useState(false);
  const [classes,   setClasses]   = useState(CLASSES);
  const [newCls,    setNewCls]    = useState('');
  const [form, setForm] = useState({ name:'', parent:'', phone:'', email:'', class_:'', prevSchool:'', regFee:'500', feePaid:false });

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const res = await registrationAPI.getAll({ limit:50 });
      setRegs(res.data.data || []); setTotal(res.data.pagination?.total || 0); setIsMock(false);
    } catch {
      setRegs(MOCK); setTotal(MOCK.length); setIsMock(true);
    } finally { setLoading(false); }
  }, []);

  useEffect(() => { load(); }, [load]);

  const handleAdd = async (e) => {
    e.preventDefault(); setSaving(true);
    try {
      await registrationAPI.create({ studentName:form.name, parentName:form.parent, mobile:form.phone, email:form.email||undefined, desiredClass:form.class_||undefined, previousSchool:form.prevSchool||undefined, registrationFee:parseInt(form.regFee)||500, feePaid:form.feePaid });
      toast.success('✅ Registration saved to database!'); setShowAdd(false);
      setForm({ name:'', parent:'', phone:'', email:'', class_:'', prevSchool:'', regFee:'500', feePaid:false }); load();
    } catch {
      const mock = { id:Date.now(), registration_no:`REG${String(regs.length+1).padStart(3,'0')}`, student_name:form.name, parent_name:form.parent, mobile:form.phone, desired_class:form.class_, registration_fee:parseInt(form.regFee)||500, fee_paid:form.feePaid, created_at:new Date().toISOString().split('T')[0], status:'pending' };
      setRegs(p=>[mock,...p]); toast.success('Registration added (demo mode)'); setShowAdd(false); setIsMock(true);
    } finally { setSaving(false); }
  };

  const handleConvert = async (reg) => {
    setSaving(true);
    try {
      await registrationAPI.convert(reg.id);
      toast.success(`🎓 ${reg.student_name} converted! Now add full details in Students.`);
      setRegs(p=>p.map(r=>r.id===reg.id?{...r,status:'converted'}:r));
    } catch {
      setRegs(p=>p.map(r=>r.id===reg.id?{...r,status:'converted'}:r));
      toast.success('Converted (demo mode)');
    } finally { setSaving(false); setConverting(null); setTimeout(()=>navigate('/students'),1200); }
  };

  const handleAddClass = () => {
    if (!newCls.trim()) return;
    if (classes.includes(newCls.trim())) { toast.error('Already exists!'); return; }
    setClasses(p=>[...p,newCls.trim()]); toast.success(`Class "${newCls.trim()}" added`); setNewCls(''); setShowAddCls(false);
  };

  const pending   = regs.filter(r=>r.status==='pending').length;
  const converted = regs.filter(r=>r.status==='converted').length;
  const feePaid   = regs.filter(r=>r.fee_paid).length;

  return (
    <div>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:16}}>
        <div>
          <h2 style={{fontSize:20,fontWeight:700,color:'#111827'}}>Registration Management</h2>
          <p style={{fontSize:12,color:'#6B7280',marginTop:2}}>
            {total} registrations
            {isMock ? <span style={{marginLeft:8,padding:'2px 8px',background:'#FEF3C7',color:'#92400E',borderRadius:10,fontSize:10,fontWeight:700}}>Demo mode</span>
                    : <span style={{marginLeft:8,padding:'2px 8px',background:'#D1FAE5',color:'#065F46',borderRadius:10,fontSize:10,fontWeight:700}}>🟢 Live DB</span>}
          </p>
        </div>
        <div style={{display:'flex',gap:10}}>
          <button onClick={()=>setShowAddCls(true)} style={{padding:'9px 14px',border:'1.5px solid #1E1B4B',borderRadius:9,background:'#EDE9F8',color:'#1E1B4B',fontSize:12,fontWeight:700,cursor:'pointer'}}>+ Add Class</button>
          <button onClick={()=>setShowAdd(true)} style={{padding:'9px 20px',background:'#1E1B4B',color:'#fff',border:'none',borderRadius:9,fontSize:13,fontWeight:700,cursor:'pointer'}}>+ New Registration</button>
        </div>
      </div>

      <div style={{display:'flex',alignItems:'center',gap:8,padding:'10px 14px',background:'#EDE9F8',borderRadius:10,marginBottom:14,fontSize:12,color:'#1E1B4B',fontWeight:600}}>
        <span>📞 Enquiry</span><span style={{color:'#A78BFA',fontSize:16}}>→</span>
        <span style={{fontWeight:800,textDecoration:'underline'}}>📄 Registration</span><span style={{color:'#A78BFA',fontSize:16}}>→</span>
        <span>🎓 Admission</span>
      </div>

      <div style={{display:'grid',gridTemplateColumns:'repeat(4,1fr)',gap:12,marginBottom:16}}>
        {[['Total',regs.length,'#EDE9F8','#1E1B4B'],['Pending',pending,'#FEF3C7','#92400E'],['Converted',converted,'#D1FAE5','#065F46'],['Fee Paid',feePaid,'#DBEAFE','#1E40AF']].map(([l,v,bg,c])=>(
          <div key={l} style={{padding:'14px',background:bg,borderRadius:12,textAlign:'center'}}>
            <div style={{fontSize:24,fontWeight:800,color:c,lineHeight:1}}>{v}</div>
            <div style={{fontSize:11,color:c,marginTop:4,fontWeight:600}}>{l}</div>
          </div>
        ))}
      </div>

      <div style={{background:'#fff',border:'0.5px solid #E5E7EB',borderRadius:14,overflow:'hidden'}}>
        <table style={{width:'100%',borderCollapse:'collapse',fontSize:12}}>
          <thead><tr style={{background:'#F9FAFB'}}>
            {['Reg No','Student','Parent / Mobile','Class','Reg Fee','Date','Status','Action'].map(h=>(
              <th key={h} style={{padding:'10px 12px',textAlign:'left',color:'#6B7280',fontSize:10,fontWeight:700,textTransform:'uppercase',borderBottom:'1px solid #E5E7EB',whiteSpace:'nowrap'}}>{h}</th>
            ))}
          </tr></thead>
          <tbody>
            {loading && <tr><td colSpan={8} style={{padding:36,textAlign:'center',color:'#9CA3AF'}}>⏳ Loading…</td></tr>}
            {!loading && regs.length===0 && <tr><td colSpan={8} style={{padding:48,textAlign:'center',color:'#9CA3AF'}}>
              <div style={{fontSize:36,marginBottom:8}}>📄</div>No registrations yet
            </td></tr>}
            {!loading && regs.map(r=>(
              <tr key={r.id} style={{borderBottom:'0.5px solid #F3F4F6',transition:'background .1s'}}
                onMouseEnter={e=>e.currentTarget.style.background='#F5F3FF'}
                onMouseLeave={e=>e.currentTarget.style.background=''}>
                <td style={{padding:'10px 12px',fontFamily:'monospace',fontSize:11,color:'#9CA3AF'}}>{r.registration_no}</td>
                <td style={{padding:'10px 12px',fontWeight:700,color:'#111827'}}>{r.student_name}</td>
                <td style={{padding:'10px 12px'}}><div style={{fontWeight:500}}>{r.parent_name}</div><div style={{fontSize:10,color:'#9CA3AF'}}>{r.mobile}</div></td>
                <td style={{padding:'10px 12px',color:'#6B7280'}}>{r.desired_class||'—'}</td>
                <td style={{padding:'10px 12px'}}>
                  <div style={{fontWeight:700}}>₹{r.registration_fee}</div>
                  <span style={{padding:'1px 6px',borderRadius:10,fontSize:9,background:r.fee_paid?'#D1FAE5':'#FEE2E2',color:r.fee_paid?'#065F46':'#991B1B',fontWeight:700}}>{r.fee_paid?'✓ Paid':'Unpaid'}</span>
                </td>
                <td style={{padding:'10px 12px',color:'#6B7280',fontSize:11}}>{r.created_at?.split('T')[0]}</td>
                <td style={{padding:'10px 12px'}}>
                  <span style={{padding:'3px 9px',borderRadius:20,fontSize:10,fontWeight:700,background:r.status==='converted'?'#D1FAE5':'#FEF3C7',color:r.status==='converted'?'#065F46':'#92400E'}}>
                    {r.status==='converted'?'✅ Admitted':'⏳ Pending'}
                  </span>
                </td>
                <td style={{padding:'10px 12px'}}>
                  {r.status==='pending'
                    ? <button onClick={()=>setConverting(r)} style={{padding:'5px 12px',background:'#1E1B4B',color:'#fff',border:'none',borderRadius:7,fontSize:11,fontWeight:700,cursor:'pointer'}}>→ Admit</button>
                    : <button onClick={()=>navigate('/students')} style={{padding:'5px 12px',border:'1px solid #E5E7EB',borderRadius:7,background:'#fff',fontSize:11,cursor:'pointer'}}>View</button>}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
        <div style={{padding:'9px 14px',borderTop:'0.5px solid #E5E7EB',fontSize:11,color:'#6B7280'}}>{total} total · {converted} admitted</div>
      </div>

      {/* Convert confirm */}
      {converting&&(
        <div style={{position:'fixed',inset:0,background:'rgba(15,23,42,.45)',zIndex:500,display:'flex',alignItems:'center',justifyContent:'center',padding:20}}>
          <div style={{background:'#fff',borderRadius:18,width:440,overflow:'hidden'}}>
            <div style={{padding:'16px 20px',borderBottom:'0.5px solid #E5E7EB',display:'flex',justifyContent:'space-between',alignItems:'center'}}>
              <div style={{fontWeight:700,fontSize:15}}>🎓 Confirm Admission</div>
              <button onClick={()=>setConverting(null)} style={{background:'#F3F4F6',border:'none',borderRadius:8,width:32,height:32,cursor:'pointer',fontSize:16}}>✕</button>
            </div>
            <div style={{padding:20}}>
              <div style={{padding:14,background:'#EDE9F8',borderRadius:12,marginBottom:14}}>
                <div style={{fontWeight:800,fontSize:15,color:'#1E1B4B',marginBottom:6}}>{converting.student_name}</div>
                <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:6,fontSize:12}}>
                  {[['Parent',converting.parent_name],['Phone',converting.mobile],['Class',converting.desired_class||'—'],['Reg No',converting.registration_no]].map(([k,v])=>(
                    <div key={k}><span style={{color:'#6B7280'}}>{k}: </span><strong>{v}</strong></div>
                  ))}
                </div>
              </div>
              <div style={{padding:'10px 12px',background:'#FEF3C7',borderRadius:9,marginBottom:14,fontSize:12,color:'#92400E'}}>
                ⚠️ This marks the registration as converted. Complete full student details in the Students module.
              </div>
              <div style={{display:'flex',gap:10}}>
                <button onClick={()=>setConverting(null)} style={{flex:1,padding:'11px',border:'1.5px solid #E5E7EB',borderRadius:10,background:'#fff',fontSize:13,cursor:'pointer'}}>Cancel</button>
                <button onClick={()=>handleConvert(converting)} disabled={saving} style={{flex:2,padding:'11px',background:saving?'#9CA3AF':'#1E1B4B',color:'#fff',border:'none',borderRadius:10,fontSize:13,fontWeight:800,cursor:'pointer'}}>
                  {saving?'⏳ Processing…':'🎓 Confirm Admission →'}
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Add class modal */}
      {showAddCls&&(
        <div style={{position:'fixed',inset:0,background:'rgba(15,23,42,.45)',zIndex:500,display:'flex',alignItems:'center',justifyContent:'center',padding:16}}>
          <div style={{background:'#fff',borderRadius:18,width:400,overflow:'hidden'}}>
            <div style={{padding:'16px 20px',borderBottom:'0.5px solid #E5E7EB',display:'flex',justifyContent:'space-between',alignItems:'center'}}>
              <div style={{fontWeight:700,fontSize:15}}>+ Add New Class</div>
              <button onClick={()=>setShowAddCls(false)} style={{background:'#F3F4F6',border:'none',borderRadius:8,width:32,height:32,cursor:'pointer',fontSize:16}}>✕</button>
            </div>
            <div style={{padding:20}}>
              <div style={{marginBottom:12}}><label style={lbl}>Class Name *</label><input value={newCls} onChange={e=>setNewCls(e.target.value)} placeholder="e.g. Class 6, LKG, Nursery" style={inp} autoFocus onKeyDown={e=>e.key==='Enter'&&handleAddClass()}/></div>
              <div style={{marginBottom:14}}><div style={{fontSize:11,fontWeight:700,color:'#6B7280',marginBottom:6}}>Existing:</div><div style={{display:'flex',flexWrap:'wrap',gap:5}}>{classes.map(c=><span key={c} style={{padding:'2px 9px',background:'#EDE9F8',borderRadius:20,fontSize:11,color:'#1E1B4B'}}>{c}</span>)}</div></div>
              <div style={{display:'flex',gap:10,justifyContent:'flex-end'}}>
                <button onClick={()=>setShowAddCls(false)} style={{padding:'9px 16px',border:'1.5px solid #E5E7EB',borderRadius:9,background:'#fff',fontSize:13,cursor:'pointer'}}>Cancel</button>
                <button onClick={handleAddClass} style={{padding:'9px 20px',background:'#1E1B4B',color:'#fff',border:'none',borderRadius:9,fontSize:13,fontWeight:700,cursor:'pointer'}}>+ Add</button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Add registration modal */}
      {showAdd&&(
        <div style={{position:'fixed',inset:0,background:'rgba(15,23,42,.45)',zIndex:500,display:'flex',alignItems:'center',justifyContent:'center',padding:16}}>
          <div style={{background:'#fff',borderRadius:18,width:540,maxHeight:'90vh',overflow:'auto'}}>
            <div style={{padding:'16px 20px',borderBottom:'0.5px solid #E5E7EB',display:'flex',justifyContent:'space-between',alignItems:'center',position:'sticky',top:0,background:'#fff'}}>
              <div style={{fontWeight:700,fontSize:15}}>📄 New Registration</div>
              <button onClick={()=>setShowAdd(false)} style={{background:'#F3F4F6',border:'none',borderRadius:8,width:32,height:32,cursor:'pointer',fontSize:16}}>✕</button>
            </div>
            <form onSubmit={handleAdd} style={{padding:20}}>
              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12,marginBottom:12}}>
                <div><label style={lbl}>Student Name *</label><input required value={form.name} onChange={e=>setForm({...form,name:e.target.value})} style={inp} autoFocus/></div>
                <div><label style={lbl}>Parent Name *</label><input required value={form.parent} onChange={e=>setForm({...form,parent:e.target.value})} style={inp}/></div>
              </div>
              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12,marginBottom:12}}>
                <div><label style={lbl}>Mobile *</label><input required value={form.phone} onChange={e=>setForm({...form,phone:e.target.value})} maxLength={10} style={inp}/></div>
                <div><label style={lbl}>Email</label><input type="email" value={form.email} onChange={e=>setForm({...form,email:e.target.value})} style={inp}/></div>
              </div>
              <div style={{display:'grid',gridTemplateColumns:'1fr auto',gap:10,alignItems:'end',marginBottom:12}}>
                <div><label style={lbl}>Class *</label>
                  <select required value={form.class_} onChange={e=>setForm({...form,class_:e.target.value})} style={inp}>
                    <option value="">Select class</option>{classes.map(c=><option key={c}>{c}</option>)}
                  </select>
                  <div style={{fontSize:10,color:'#9CA3AF',marginTop:3}}>Not in list? Click + to add</div>
                </div>
                <button type="button" onClick={()=>setShowAddCls(true)} style={{padding:'10px 14px',border:'1.5px solid #1E1B4B',borderRadius:9,background:'#EDE9F8',color:'#1E1B4B',fontWeight:800,cursor:'pointer',fontSize:18,height:44}}>+</button>
              </div>
              <div style={{marginBottom:12}}><label style={lbl}>Previous School</label><input value={form.prevSchool} onChange={e=>setForm({...form,prevSchool:e.target.value})} style={inp}/></div>
              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12,marginBottom:16}}>
                <div><label style={lbl}>Registration Fee (₹)</label><input type="number" value={form.regFee} onChange={e=>setForm({...form,regFee:e.target.value})} style={inp}/></div>
                <div style={{display:'flex',alignItems:'center',gap:10,paddingTop:24}}>
                  <input type="checkbox" id="fp" checked={form.feePaid} onChange={e=>setForm({...form,feePaid:e.target.checked})} style={{width:18,height:18,accentColor:'#1E1B4B',cursor:'pointer'}}/>
                  <label htmlFor="fp" style={{fontSize:13,fontWeight:600,cursor:'pointer'}}>Fee Paid</label>
                </div>
              </div>
              <div style={{display:'flex',gap:10,justifyContent:'flex-end'}}>
                <button type="button" onClick={()=>setShowAdd(false)} style={{padding:'10px 16px',border:'1.5px solid #E5E7EB',borderRadius:9,background:'#fff',fontSize:13,cursor:'pointer'}}>Cancel</button>
                <button type="submit" disabled={saving} style={{padding:'10px 22px',background:saving?'#9CA3AF':'#1E1B4B',color:'#fff',border:'none',borderRadius:9,fontSize:13,fontWeight:700,cursor:'pointer'}}>{saving?'⏳ Saving…':'💾 Save Registration'}</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
